enum HttpStatus {
  OK = 200,
  Created = 201,
  BadRequest = 400,
  Unauthorized = 401,
  NotFound = 404,
  InternalServerError = 500
}

function handleResponse(status: HttpStatus): string {
  switch (status) {
    case HttpStatus.OK:
      return "Success";
    case HttpStatus.NotFound:
      return "Not Found";
    case HttpStatus.InternalServerError:
      return "Server Error";
    default:
      return "Unknown";
  }
}

console.log(handleResponse(HttpStatus.OK)); // Success
console.log(HttpStatus[200]); // "OK" (reverse mapping)
